import test from 'node:test';
import assert from 'node:assert/strict';
import { fileURLToPath } from 'node:url';

import { PluginRegistry } from '../src/plugin-registry.mjs';

test('registry activation uses the deployed module for a scoped vendor bundle', async () => {
  const packageRoot = fileURLToPath(
    new URL('./final_data/vendor%23suite/', import.meta.url)
  );
  const registry = new PluginRegistry();

  const plugin = await registry.activate('vendor-suite', packageRoot);

  assert.deepEqual(plugin, {
    runtime: 'node',
    hooks: ['startup', 'shutdown']
  });
  assert.strictEqual(registry.get('vendor-suite'), plugin);
});
